SELECT * FROM word_bank
WHERE deleted_at IS NULL
  AND audit_status = 1
  AND level_code = #{levelCode}

      AND id NOT IN

          #{id}




        ORDER BY topic_code ASC, word_lower ASC


        ORDER BY RAND()


        ORDER BY word_lower ASC


LIMIT #{limit}

SELECT * FROM word_bank
WHERE deleted_at IS NULL
  AND audit_status = 1
  AND level_code = #{levelCode}
  AND id != #{excludeId}

      AND topic_code = #{topicCode}

ORDER BY RAND()
LIMIT #{limit}

SELECT * FROM word_bank
WHERE deleted_at IS NULL
  AND audit_status = 1
  AND level_code = #{levelCode}

      AND updated_at > #{since}

ORDER BY id ASC
